@startuml
title SeismicAttributeType Outgoing Relationships View

package "SeismicAttributeType Outgoing Relationships View" {
    class "SeismicAttributeType" as SeismicAttributeType <<reference-data>> {
        + NameAlias[]
    }

    class "AbstractReferenceType" as AbstractReferenceType <<Abstraction>> {
    }

    class "NameAlias[]" as NameAlias <<nested array>> {
        + DefinitionOrganisationID
    }

    class "Organisation" as Organisation <<master-data>> {
    }

    class "Reference Data Relationships" as ReferenceDataRelationships <<reference-data>> {
        + "data.NameAlias[].AliasNameTypeID" -> AliasNameType
        + "data.NameAlias[].DefinitionOrganisationID" -> StandardsOrganisation
    }

    SeismicAttributeType --|> AbstractReferenceType
    SeismicAttributeType *-- NameAlias : *
    NameAlias --> Organisation : DefinitionOrganisationID
    SeismicAttributeType ..> ReferenceDataRelationships
}

@enduml
